const getLayerTotalCount = (list,count) => {

// 配置选项的映射
const propsMap = {
  children: 'children',
  label: 'name',
};

// 获取图层总数（只计算叶子节点，不包括父节点）
let currentCount = count;
list.forEach((item) => {
  /* 检查是否有children且不为空 */
  if (item[propsMap.children] && item[propsMap.children].length > 0) {
    // 对于有子节点的父节点，只递归遍历子节点，但不计数父节点本身
    currentCount = getLayerTotalCount(item[propsMap.children], currentCount);
  } else {
    // 对于没有子节点或子节点为空的叶子节点，进行计数
    currentCount += 1;
  }
});
return currentCount;
};
